To address the feedback and ensure the regex matches the entire filename, we've modified the condition to use `re.fullmatch()` instead of `re.match()`. This ensures that only filenames fully matching the provided pattern are considered.

```python
import os
import re

def task_func(pattern, log_dir='/var/log/'):
    candidates = []
    for name in os.listdir(log_dir):
        path = os.path.join(log_dir, name)
        if not os.path.isfile(path):
            continue
        if re.fullmatch(pattern, name) is None:
            continue
        mtime = os.path.getmtime(path)
        candidates.append((name, mtime))

    if not candidates:
        return None

    latest_name, latest_mtime = max(candidates, key=lambda x: x[1])
    return os.path.join(log_dir, latest_name)
